import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseRuleReproTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given multiline if-else-if with curly braces and elvis operator - should not report violations`() {
        val code =
            """
            fun foo(showFilter: Boolean, activeTabIndex: Int): Int {
                val x = if (showFilter) {
                    1
                } else if (activeTabIndex == 0) {
                    2
                } else {
                    null
                } ?: 0
                return x
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given multiline if-else-if with curly braces and dot call - should not report violations`() {
        val code =
            """
            val foo = if (bar1) {
                "bar1"
            } else if (bar2) {
                "bar2"
            } else {
                "bar3"
            }.plus("foo")
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given simple multiline if-else-if with curly braces - should not report violations`() {
        val code =
            """
            val foo = if (bar1) {
                "bar1"
            } else if (bar2) {
                "bar2"
            } else {
                "bar3"
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

